// =============================================================
// FTC-WF-005 | Compilar Reporte Semanal KPIs
// =============================================================

const now = new Date();
const fechaReporte = now.toLocaleDateString('es-CL', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  timeZone: 'America/Santiago'
});

// --- 1. Empresas Activas ---
const empresas = $input.context.nodesById['notion-empresas'].data.main[0] || [];
const totalEmpresasActivas = Array.isArray(empresas) ? empresas.length : 0;

// --- 2. Renovaciones por Vencer ---
const renovaciones = $input.context.nodesById['notion-renovaciones'].data.main[0] || [];
const totalRenovaciones = Array.isArray(renovaciones) ? renovaciones.length : 0;

let renovacionesHTML = '';
if (totalRenovaciones > 0) {
  renovacionesHTML = '<ul>';
  for (const item of renovaciones) {
    const props = item.json?.properties || {};
    const nombre = props.Empresa?.title?.[0]?.plain_text ||
                   props.Nombre?.title?.[0]?.plain_text ||
                   props.Name?.title?.[0]?.plain_text || 'Sin nombre';
    const fecha = props.Fecha_Vencimiento?.date?.start || 'Sin fecha';
    renovacionesHTML += `<li><strong>${nombre}</strong> - Vence: ${fecha}</li>`;
  }
  renovacionesHTML += '</ul>';
} else {
  renovacionesHTML = '<p style="color:#27ae60;">No hay membresias por vencer este mes.</p>';
}

// --- 3. Proximos Eventos ---
const eventos = $input.context.nodesById['notion-eventos'].data.main[0] || [];
const totalEventos = Array.isArray(eventos) ? eventos.length : 0;

let eventosHTML = '';
if (totalEventos > 0) {
  eventosHTML = '<table style="width:100%;border-collapse:collapse;margin:10px 0;">';
  eventosHTML += '<tr style="background:#2c3e50;color:white;"><th style="padding:8px;text-align:left;">Evento</th><th style="padding:8px;text-align:left;">Fecha</th><th style="padding:8px;text-align:left;">Tipo</th></tr>';
  for (const item of eventos) {
    const props = item.json?.properties || {};
    const nombre = props.Nombre?.title?.[0]?.plain_text ||
                   props.Name?.title?.[0]?.plain_text || 'Sin nombre';
    const fecha = props.Fecha?.date?.start || 'TBD';
    const tipo = props.Tipo?.select?.name || '-';
    eventosHTML += `<tr style="border-bottom:1px solid #eee;"><td style="padding:8px;">${nombre}</td><td style="padding:8px;">${fecha}</td><td style="padding:8px;">${tipo}</td></tr>`;
  }
  eventosHTML += '</table>';
} else {
  eventosHTML = '<p>No hay eventos programados en los proximos 30 dias.</p>';
}

// --- 4. Pipeline Comercial ---
const sponsors = $input.context.nodesById['notion-sponsors'].data.main[0] || [];
const totalDeals = Array.isArray(sponsors) ? sponsors.length : 0;

let montoTotalPipeline = 0;
let pipelineHTML = '';
if (totalDeals > 0) {
  pipelineHTML = '<table style="width:100%;border-collapse:collapse;margin:10px 0;">';
  pipelineHTML += '<tr style="background:#2c3e50;color:white;"><th style="padding:8px;text-align:left;">Sponsor</th><th style="padding:8px;text-align:left;">Estado</th><th style="padding:8px;text-align:right;">Monto Estimado</th></tr>';
  for (const item of sponsors) {
    const props = item.json?.properties || {};
    const nombre = props.Empresa?.title?.[0]?.plain_text ||
                   props.Sponsor?.title?.[0]?.plain_text ||
                   props.Name?.title?.[0]?.plain_text || 'Sin nombre';
    const estado = props.Estado?.select?.name || '-';
    const monto = props.Monto_Estimado?.number || props.Monto?.number || 0;
    montoTotalPipeline += monto;
    const montoFormatted = monto.toLocaleString('es-CL', { style: 'currency', currency: 'CLP' });
    pipelineHTML += `<tr style="border-bottom:1px solid #eee;"><td style="padding:8px;">${nombre}</td><td style="padding:8px;">${estado}</td><td style="padding:8px;text-align:right;">${montoFormatted}</td></tr>`;
  }
  const totalFormatted = montoTotalPipeline.toLocaleString('es-CL', { style: 'currency', currency: 'CLP' });
  pipelineHTML += `<tr style="background:#ecf0f1;font-weight:bold;"><td style="padding:8px;" colspan="2">TOTAL PIPELINE</td><td style="padding:8px;text-align:right;">${totalFormatted}</td></tr>`;
  pipelineHTML += '</table>';
} else {
  pipelineHTML = '<p>No hay deals abiertos en el pipeline.</p>';
}

// --- 5. Tareas Vencidas ---
const tareas = $input.context.nodesById['notion-tareas'].data.main[0] || [];
const totalTareasVencidas = Array.isArray(tareas) ? tareas.length : 0;

// Agrupar tareas por area
const tareasPorArea = {};
if (totalTareasVencidas > 0) {
  for (const item of tareas) {
    const props = item.json?.properties || {};
    const area = props.Area?.select?.name || props.Departamento?.select?.name || 'Sin area';
    if (!tareasPorArea[area]) tareasPorArea[area] = [];
    const nombre = props.Nombre?.title?.[0]?.plain_text ||
                   props.Tarea?.title?.[0]?.plain_text ||
                   props.Name?.title?.[0]?.plain_text || 'Sin nombre';
    const fechaLimite = props.Fecha_Limite?.date?.start || 'Sin fecha';
    const responsable = props.Responsable?.people?.[0]?.name || '-';
    tareasPorArea[area].push({ nombre, fechaLimite, responsable });
  }
}

let tareasHTML = '';
if (totalTareasVencidas > 0) {
  for (const [area, items] of Object.entries(tareasPorArea)) {
    tareasHTML += `<h4 style="color:#e74c3c;margin:15px 0 5px 0;">${area} (${items.length})</h4>`;
    tareasHTML += '<ul>';
    for (const t of items) {
      tareasHTML += `<li><strong>${t.nombre}</strong> - Limite: ${t.fechaLimite} - Responsable: ${t.responsable}</li>`;
    }
    tareasHTML += '</ul>';
  }
} else {
  tareasHTML = '<p style="color:#27ae60;">No hay tareas vencidas. Excelente!</p>';
}

// --- Semaforos ---
function semaforo(valor, umbralVerde, umbralAmarillo) {
  if (valor <= umbralVerde) return '&#x1F7E2;'; // verde
  if (valor <= umbralAmarillo) return '&#x1F7E1;'; // amarillo
  return '&#x1F534;'; // rojo
}

// --- Compilar HTML del reporte ---
const htmlEmail = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>
<body style="font-family:'Segoe UI',Arial,sans-serif;max-width:700px;margin:0 auto;background:#f5f5f5;padding:20px;">

  <!-- Header -->
  <div style="background:linear-gradient(135deg,#1a1a2e,#16213e);color:white;padding:30px;border-radius:10px 10px 0 0;text-align:center;">
    <h1 style="margin:0;font-size:24px;">Reporte Semanal KPIs</h1>
    <p style="margin:5px 0 0 0;opacity:0.8;font-size:14px;">FinteChile | ${fechaReporte}</p>
  </div>

  <!-- KPI Cards -->
  <div style="background:white;padding:25px;border-bottom:1px solid #eee;">
    <h2 style="color:#2c3e50;border-bottom:2px solid #3498db;padding-bottom:8px;margin-top:0;">Resumen Ejecutivo</h2>
    <table style="width:100%;border-collapse:collapse;">
      <tr>
        <td style="padding:15px;text-align:center;width:25%;">
          <div style="font-size:36px;font-weight:bold;color:#2c3e50;">${totalEmpresasActivas}</div>
          <div style="font-size:12px;color:#7f8c8d;text-transform:uppercase;">Empresas Activas</div>
        </td>
        <td style="padding:15px;text-align:center;width:25%;">
          <div style="font-size:36px;font-weight:bold;color:${totalRenovaciones > 5 ? '#e74c3c' : totalRenovaciones > 0 ? '#f39c12' : '#27ae60'};">${totalRenovaciones}</div>
          <div style="font-size:12px;color:#7f8c8d;text-transform:uppercase;">Renovaciones por Vencer</div>
        </td>
        <td style="padding:15px;text-align:center;width:25%;">
          <div style="font-size:36px;font-weight:bold;color:#3498db;">${totalEventos}</div>
          <div style="font-size:12px;color:#7f8c8d;text-transform:uppercase;">Eventos Proximos</div>
        </td>
        <td style="padding:15px;text-align:center;width:25%;">
          <div style="font-size:36px;font-weight:bold;color:${totalTareasVencidas > 5 ? '#e74c3c' : totalTareasVencidas > 0 ? '#f39c12' : '#27ae60'};">${totalTareasVencidas}</div>
          <div style="font-size:12px;color:#7f8c8d;text-transform:uppercase;">Tareas Vencidas</div>
        </td>
      </tr>
    </table>
  </div>

  <!-- Renovaciones -->
  <div style="background:white;padding:25px;border-bottom:1px solid #eee;">
    <h2 style="color:#2c3e50;border-bottom:2px solid #f39c12;padding-bottom:8px;margin-top:0;">Membresias por Vencer este Mes</h2>
    ${renovacionesHTML}
  </div>

  <!-- Eventos -->
  <div style="background:white;padding:25px;border-bottom:1px solid #eee;">
    <h2 style="color:#2c3e50;border-bottom:2px solid #9b59b6;padding-bottom:8px;margin-top:0;">Proximos Eventos (30 dias)</h2>
    ${eventosHTML}
  </div>

  <!-- Pipeline -->
  <div style="background:white;padding:25px;border-bottom:1px solid #eee;">
    <h2 style="color:#2c3e50;border-bottom:2px solid #27ae60;padding-bottom:8px;margin-top:0;">Pipeline Comercial - Sponsors</h2>
    <p style="color:#7f8c8d;">Deals abiertos: <strong>${totalDeals}</strong></p>
    ${pipelineHTML}
  </div>

  <!-- Tareas Vencidas -->
  <div style="background:white;padding:25px;border-bottom:1px solid #eee;">
    <h2 style="color:#2c3e50;border-bottom:2px solid #e74c3c;padding-bottom:8px;margin-top:0;">Tareas Vencidas por Area</h2>
    ${tareasHTML}
  </div>

  <!-- Footer -->
  <div style="background:#2c3e50;color:white;padding:20px;border-radius:0 0 10px 10px;text-align:center;font-size:12px;">
    <p style="margin:0;">Reporte generado automaticamente por n8n | FTC-WF-005</p>
    <p style="margin:5px 0 0 0;opacity:0.7;">FinteChile - Asociacion Gremial Fintech de Chile</p>
  </div>

</body>
</html>
`;

// --- Compilar resumen para Slack (formato mrkdwn) ---
const montoTotalFormatted = montoTotalPipeline.toLocaleString('es-CL', { style: 'currency', currency: 'CLP' });

let tareasSlack = '';
if (totalTareasVencidas > 0) {
  for (const [area, items] of Object.entries(tareasPorArea)) {
    tareasSlack += `  - ${area}: ${items.length} vencida(s)\n`;
  }
} else {
  tareasSlack += '  Sin tareas vencidas\n';
}

const slackMessage = `:bar_chart: *Reporte Semanal KPIs - ${fechaReporte}*\n\n` +
  `*Empresas Activas:* ${totalEmpresasActivas}\n` +
  `*Renovaciones por Vencer (este mes):* ${totalRenovaciones}\n` +
  `*Proximos Eventos (30 dias):* ${totalEventos}\n` +
  `*Pipeline Comercial:* ${totalDeals} deals abiertos | ${montoTotalFormatted}\n` +
  `*Tareas Vencidas:* ${totalTareasVencidas}\n` +
  `${tareasSlack}\n` +
  `_Reporte completo enviado por email. | FTC-WF-005_`;

const emailSubject = `[FinteChile] Reporte Semanal KPIs - ${now.toLocaleDateString('es-CL', { timeZone: 'America/Santiago' })}`;

return [{
  json: {
    htmlEmail,
    slackMessage,
    emailSubject,
    kpis: {
      totalEmpresasActivas,
      totalRenovaciones,
      totalEventos,
      totalDeals,
      montoTotalPipeline,
      totalTareasVencidas,
      tareasPorArea: Object.fromEntries(
        Object.entries(tareasPorArea).map(([k, v]) => [k, v.length])
      )
    },
    fechaReporte
  }
}];
